// 1. Kunin ang input mula sa mga EditText (Hero Name, Head Icon, at Portrait Link)
final EditText editName = findViewById(R.id.edit_name);
final String heroName = editName.getText().toString().trim();

final EditText editHead = findViewById(R.id.edit_head);
final String headUrl = editHead.getText().toString().trim();

final EditText editPortrait = findViewById(R.id.edit_portrait);
final String portraitUrl = editPortrait.getText().toString().trim();

if (heroName.isEmpty()) {
    SketchwareUtil.showMessage(getApplicationContext(), "Mangyaring ilagay muna ang Hero Name!");
    return;
}

if (headUrl.isEmpty()) {
    SketchwareUtil.showMessage(getApplicationContext(), "Mangyaring ilagay muna ang Head Icon Link!");
    return;
}

if (portraitUrl.isEmpty()) {
    SketchwareUtil.showMessage(getApplicationContext(), "Mangyaring ilagay muna ang Portrait Link!");
    return;
}

// Siguraduhin na pumili muna ng Lane Category ang user bago mag-save
if (lane.isEmpty()) {
    SketchwareUtil.showMessage(getApplicationContext(), "Please select a Lane Category first!");
    return;
}

// Siguraduhin na pumili muna ng Role Category ang user bago mag-save
if (role.isEmpty()) {
    SketchwareUtil.showMessage(getApplicationContext(), "Please select a Role Category first!");
    return;
}

// 2. KUNIN ANG NUMERO MULA SA IYONG CO-CODED NUMBERPICKER
String selectedHeroId = "1";
LinearLayout pickerContainer = findViewById(R.id.picker_container);

for (int i = 0; i < pickerContainer.getChildCount(); i++) {
    View child = pickerContainer.getChildAt(i);
    if (child instanceof android.widget.NumberPicker) {
        android.widget.NumberPicker dynamicPicker = (android.widget.NumberPicker) child;
        selectedHeroId = String.valueOf(dynamicPicker.getValue());
        break;
    }
}

final String heroId = selectedHeroId;
final String finalLane = lane; 
final String finalRole = role; 
final String finalHeadUrl = headUrl; 
final String finalPortraitUrl = portraitUrl; // Ipasa ang portrait link variable dito

// 3. Kunin ang mga nakasave na GitHub Info mula sa SharedPreferences (auth)
final String repoUrl = auth.getString("repo_url", ""); 
final String token = auth.getString("token", "");
final String email = auth.getString("email", "");
final String username = auth.getString("username", "");

if (repoUrl.isEmpty() || token.isEmpty()) {
    SketchwareUtil.showMessage(getApplicationContext(), "I-set up muna ang iyong GitHub Info sa settings!");
    return;
}

// Target URL para sa data.json
final String targetUrl = "https://api.github.com/repos/" + repoUrl + "/contents/data.json";

// 4. Background Thread para sa GET at PUT integration sa GitHub
new Thread(new Runnable() {
    @Override
    public void run() {
        try {
            // HAKBANG A: KUNIN ANG KASALUKUYANG LAMAN AT SHA NG DATA.JSON
            java.net.URL url = new java.net.URL(targetUrl);
            java.net.HttpURLConnection getConn = (java.net.HttpURLConnection) url.openConnection();
            getConn.setRequestMethod("GET");
            getConn.setRequestProperty("Authorization", "token " + token);
            getConn.setRequestProperty("Accept", "application/vnd.github.v3+json");

            int getResponseCode = getConn.getResponseCode();
            String currentSha = "";
            String currentJsonContent = "{}";

            if (getResponseCode == 200) {
                java.io.BufferedReader reader = new java.io.BufferedReader(new java.io.InputStreamReader(getConn.getInputStream()));
                StringBuilder sb = new StringBuilder();
                String line;
                while ((line = reader.readLine()) != null) { sb.append(line); }
                reader.close();

                org.json.JSONObject githubResponse = new org.json.JSONObject(sb.toString());
                currentSha = githubResponse.getString("sha");

                String base64Content = githubResponse.getString("content").replaceAll("\\s", "");
                byte[] decodedBytes = android.util.Base64.decode(base64Content, android.util.Base64.DEFAULT);
                currentJsonContent = new String(decodedBytes, "UTF-8");
            }
            getConn.disconnect();

            // HAKBANG B: INTEGRATION AT CHECKING KUNG EXISTING NA ANG ID
            org.json.JSONObject rootJsonObject;
            try {
                rootJsonObject = new org.json.JSONObject(currentJsonContent);
            } catch (Exception e) {
                rootJsonObject = new org.json.JSONObject();
            }

            if (rootJsonObject.has(heroId)) {
                runOnUiThread(new Runnable() {
                    @Override
                    public void run() {
                        SketchwareUtil.showMessage(getApplicationContext(), "This ID already exists!");
                    }
                });
                return; 
            }

            // ITUTULOY ANG PAG-SAVE KUNG HINDI EXISTING:
            org.json.JSONObject heroDetails = new org.json.JSONObject();
            heroDetails.put("hero_name", heroName);
            heroDetails.put("lane", finalLane); 
            heroDetails.put("role", finalRole); 
            heroDetails.put("head_icon", finalHeadUrl); 
            heroDetails.put("portrait_icon", finalPortraitUrl); // <--- BAGONG UPDATE: NAISAMA NA ANG PORTRAIT MO!

            // Isave gamit ang Hero ID key
            rootJsonObject.put(heroId, heroDetails);

            String updatedJsonStr = rootJsonObject.toString(2);
            String encodedContent = android.util.Base64.encodeToString(updatedJsonStr.getBytes("UTF-8"), android.util.Base64.NO_WRAP);

            // HAKBANG C: I-UPLOAD ANG NAI-UPDATE NA DATA.JSON SA GITHUB
            java.net.HttpURLConnection putConn = (java.net.HttpURLConnection) url.openConnection();
            putConn.setRequestMethod("PUT");
            putConn.setRequestProperty("Authorization", "token " + token);
            putConn.setRequestProperty("Content-Type", "application/json; charset=utf-8");
            putConn.setRequestProperty("Accept", "application/vnd.github.v3+json");
            putConn.setDoOutput(true);

            org.json.JSONObject putBody = new org.json.JSONObject();
            putBody.put("message", "Added Hero ID " + heroId + ": " + heroName);
            putBody.put("content", encodedContent);
            if (!currentSha.isEmpty()) {
                putBody.put("sha", currentSha);
            }
            org.json.JSONObject committer = new org.json.JSONObject();
            committer.put("name", username);
            committer.put("email", email);
            putBody.put("committer", committer);

            java.io.OutputStream os = putConn.getOutputStream();
            os.write(putBody.toString().getBytes("utf-8"));
            os.close();

            final int putResponseCode = putConn.getResponseCode();
            putConn.disconnect();

            // Balik sa UI thread para tapusin ang aksyon
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    if (putResponseCode == 200 || putResponseCode == 201) {
                        SketchwareUtil.showMessage(getApplicationContext(), "Successfully saved " + heroName + " with ID " + heroId + "!");
                        editName.setText(""); 
                        editHead.setText(""); 
                        editPortrait.setText(""); // I-clear din ang text box ng portrait link pagkatapos mag-save
                        lane = ""; 
                        role = ""; 

                        // I-RESET ANG LAHAT NG LANE AT ROLE BUTTONS PABALIK SA PUTI
                        int[] allButtons = {
                            R.id.explinear, R.id.midlinear, R.id.roamlinear, R.id.junglelinear, R.id.goldlinear,
                            R.id.tanklinear, R.id.fighterlinear, R.id.assassinlinear, R.id.magelinear, R.id.marksmanlinear, R.id.supportlinear
                        };

                        for (int id : allButtons) {
                            View v = findViewById(id);
                            if (v != null) {
                                android.graphics.drawable.GradientDrawable gd = new android.graphics.drawable.GradientDrawable();
                                gd.setColor(Color.parseColor("#FFFFFF")); 
                                gd.setCornerRadius(20); 
                                gd.setStroke(2, Color.parseColor("#FF000000")); 
                                v.setBackground(gd);
                            }
                        }
                    } else {
                        SketchwareUtil.showMessage(getApplicationContext(), "Upload failed: Code " + putResponseCode);
                    }
                }
            });

        } catch (final Exception e) {
            runOnUiThread(new Runnable() {
                @Override
                public void run() {
                    SketchwareUtil.showMessage(getApplicationContext(), "Error: " + e.getMessage());
                }
            });
        }
    }
}).start();

